"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[7680],{99939:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":"Creates a new BulletContext.\\n\\n`Origin`, `Direction`, and `Speed` are required. `SolverData` is reserved\\nfor internal solver use \u2014 do not supply it from weapon code.","params":[{"name":"config","desc":"","lua_type":"BulletContextConfig"}],"returns":[{"desc":"","lua_type":"BulletContext"}],"function_type":"static","source":{"line":183,"path":"docs/BulletContext.lua"}},{"name":"IsAlive","desc":"Returns whether the bullet is still alive and being simulated.","params":[],"returns":[{"desc":"","lua_type":"boolean"}],"function_type":"method","source":{"line":192,"path":"docs/BulletContext.lua"}},{"name":"GetLifetime","desc":"Returns how many seconds this bullet has been simulated.\\n\\nTracks `SimulationTime` accumulated by the solver \u2014 not real-world clock\\ntime. Does not advance while the cast is paused.","params":[],"returns":[{"desc":"Simulated age in seconds.","lua_type":"number"}],"function_type":"method","source":{"line":202,"path":"docs/BulletContext.lua"}},{"name":"GetDistanceTraveled","desc":"Returns the true accumulated path length of the bullet in studs.\\n\\nUnlike `(Position - Origin).Magnitude`, this correctly accounts for\\nbounces and homing curves by accumulating the actual frame-by-frame\\ndisplacement. Equivalent to reading `context.Length`.","params":[],"returns":[{"desc":"Path length in studs.","lua_type":"number"}],"function_type":"method","source":{"line":213,"path":"docs/BulletContext.lua"}},{"name":"GetSnapshot","desc":"Returns a read-only snapshot of the bullet\'s current state.\\n\\nUseful for logging, replication, or passing state to systems that\\nshould not hold a live reference to the context.","params":[],"returns":[{"desc":"","lua_type":"BulletSnapshot"}],"function_type":"method","source":{"line":223,"path":"docs/BulletContext.lua"}},{"name":"Terminate","desc":"Terminates the bullet immediately, notifying the solver to clean up\\nresources, destroy the cosmetic object, and fire `OnTerminated`.\\n\\nCalling `Terminate` on an already-dead bullet is a no-op.","params":[],"returns":[],"function_type":"method","source":{"line":231,"path":"docs/BulletContext.lua"}}],"properties":[{"name":"Id","desc":"Auto-incrementing unique identifier assigned at construction time.\\nUse this to distinguish bullets in signal handlers without storing\\nseparate references.","lua_type":"number","readonly":true,"source":{"line":41,"path":"docs/BulletContext.lua"}},{"name":"Origin","desc":"World-space muzzle position at the moment the bullet was fired. Never changes.","lua_type":"Vector3","readonly":true,"source":{"line":49,"path":"docs/BulletContext.lua"}},{"name":"Direction","desc":"Unit direction vector the bullet was fired along. Never changes.","lua_type":"Vector3","readonly":true,"source":{"line":57,"path":"docs/BulletContext.lua"}},{"name":"Speed","desc":"Initial speed in studs per second. The bullet\'s actual speed decreases\\nover time due to drag, bounces (restitution), and pierces (speed retention).\\nRead the magnitude of `Velocity` for the current speed.","lua_type":"number","readonly":true,"source":{"line":67,"path":"docs/BulletContext.lua"}},{"name":"StartTime","desc":"`os.clock()` timestamp at construction. Use with [BulletContext:GetLifetime]\\nto compute bullet age without storing the time yourself.","lua_type":"number","readonly":true,"source":{"line":76,"path":"docs/BulletContext.lua"}},{"name":"RaycastParams","desc":"Optional per-bullet raycast filter. When set, used as the raycast params\\nfor this bullet if the Behavior does not have its own `RaycastParams` set.\\n\\nPriority order in [Vetra:Fire]:\\n1. `Behavior.RaycastParams` \u2014 if the user called `:RaycastParams()` on the BehaviorBuilder.\\n2. `BulletContext.RaycastParams` \u2014 this field.\\n3. Default empty `RaycastParams.new()`.\\n\\nUseful when you share a single Behavior across many bullet types but need\\nper-bullet filtering (e.g. different ignore lists per shooter).","lua_type":"RaycastParams?","readonly":true,"source":{"line":93,"path":"docs/BulletContext.lua"}},{"name":"Position","desc":"Current world-space position. Updated every frame by the solver.\\n`nil` until the first simulation step.","lua_type":"Vector3?","readonly":true,"source":{"line":102,"path":"docs/BulletContext.lua"}},{"name":"Velocity","desc":"Current velocity vector in studs per second. Updated every frame by the\\nsolver. The magnitude of this vector is the current speed.","lua_type":"Vector3","readonly":true,"source":{"line":111,"path":"docs/BulletContext.lua"}},{"name":"Alive","desc":"`true` while the cast is being simulated. Set to `false` by\\n[BulletContext:Terminate] or automatically by the solver on hit,\\ndistance expiry, speed expiry, or corner-trap detection.","lua_type":"boolean","readonly":true,"source":{"line":121,"path":"docs/BulletContext.lua"}},{"name":"Length","desc":"True accumulated path distance in studs \u2014 the sum of every frame\\ndisplacement since firing. This diverges from straight-line\\n`(Position - Origin).Magnitude` for bullets that bounce or follow\\nhoming curves. See also [BulletContext:GetDistanceTraveled].","lua_type":"number","readonly":true,"source":{"line":132,"path":"docs/BulletContext.lua"}},{"name":"SimulationTime","desc":"Total seconds this bullet has been simulated, as tracked by the solver.\\nUpdated every frame. Use [BulletContext:GetLifetime] to read this.\\nDoes not advance while the cast is paused.","lua_type":"number","readonly":true,"source":{"line":142,"path":"docs/BulletContext.lua"}},{"name":"CosmeticBulletObject","desc":"Set by the solver after the cosmetic bullet is created. Readable from\\nsignal handlers (`OnSegmentOpen`, `OnBounce`, etc.) via the context argument.\\n`nil` when no cosmetic is configured or after the bullet terminates.","lua_type":"Instance?","readonly":true,"source":{"line":152,"path":"docs/BulletContext.lua"}},{"name":"UserData","desc":"Free-form table for attaching cast-specific metadata (shooter UserId,\\nweapon type, damage value, etc.). Surfaced on every signal emission \u2014\\nread it in your handlers to route events without maintaining a parallel lookup.\\n\\n```lua\\ncontext.UserData.Damage    = 45\\ncontext.UserData.ShooterId = Players.LocalPlayer.UserId\\n\\nSignals.OnHit:Connect(function(context, result, velocity)\\n    local damage    = context.UserData.Damage\\n    local shooterId = context.UserData.ShooterId\\nend)\\n```","lua_type":"{[any]: any}","source":{"line":171,"path":"docs/BulletContext.lua"}}],"types":[],"name":"BulletContext","desc":"The public-facing object that weapon code interacts with for every\\nin-flight projectile.\\n\\nCreate one before firing, pass it to [Vetra:Fire], then use the\\nsolver\'s signals to react to events. The context is passed as the\\nfirst argument on every signal so you can identify the bullet and\\nread its current state.\\n\\n```lua\\nlocal context = BulletContext.new({\\n    Origin    = muzzlePosition,\\n    Direction = direction,\\n    Speed     = 200,\\n})\\n\\nSolver:Fire(context, Behavior)\\n```\\n\\n:::tip UserData\\nAttach weapon-specific metadata (shooter UserId, damage value, hit-group\\nflags, etc.) via `context.UserData` before calling `Fire`. This table is\\npassed unchanged on every signal emission.\\n:::","source":{"line":28,"path":"docs/BulletContext.lua"}}')}}]);